      /* <flatten type="Javascript"> */
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  var l = (f.getItemValue('nam') == 0);
  if (l) {
    f.getItem('tu_ky').value = f.getItem('den_ky').value = (new Date()).getMonth() + 1;
    f.getItem('nam').value = f.getItem('nam2').value = (new Date()).getFullYear();
  }
  f.live(f.getItem('tu_ky'));
  if (!l) onChange$Filter$ReportForm(f.getItem('ma_dvcs'));
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
   var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, x = f.getItemValue('mau_bc');
      var d1 = f.getItem('tu_ky').value, d2 = f.getItem('den_ky').value, n1 = f.getItem('nam').value, n2 = f.getItem('nam2').value;
      g._alterTitle = [null, [['%d1', d1, true], ['%n1', n1, true],['%d2', d2, true], ['%n2', n2, true]]];
      g._hiddenFields = [{Fields: 'ma_bp', Value: (!f._costDept)}, {Fields: 'so_lsx', Value: (!f._costMO)}];
      g._hiddenForms = [
        {Form: [2, 3, 4, 5, 6, 7, 11, 12, 13, 14, 15, 16], Value: (f._costDept && f._costMO)},
        {Form: [0, 1, 4, 5, 6, 7, 9, 10, 13, 14, 15, 16], Value: (f._costDept && !f._costMO)},
        {Form: [0, 1, 2, 3, 6, 7, 9, 10, 11, 12, 15, 16], Value: (!f._costDept && f._costMO)},
        {Form: [0, 1, 2, 3, 4, 5, 9, 10, 11, 12, 13, 14], Value: (!f._costDept && !f._costMO)}
      ];
      var c = f.getItemValue('mau_bc');
      if (!g._v) g._v = c;
      if (g._v != c) {
        remove$GridReport$Filter(g);
        g._v = c;
      }
      break;
    case 'SetReadOnlyField':
      f._costDept = result[0].Value;
      f._costMO = result[1].Value;
      setItemReadOnly(f, 'ma_bp', result[0].Value, false);
      setItemReadOnly(f, 'so_lsx', result[1].Value, false);
      break;
    default:
      break;
  }
}
function onChange$Filter$ReportForm(o) {if (o.parentForm._objectUnit == '1') o.parentForm.request('GetResponse', 'SetReadOnlyField', ['ma_dvcs'])}
